mapper.update:
UPDATE center
SET center_code          = #{centerCode}
  , center_name          = #{centerName}
  , head                 = #{head}
  , telephone            = #{telephone}
  , homepage             = #{homepage}
  , zipcode              = #{zipcode}
  , sido                 = #{sido}
  , sigungu              = #{sigungu}
  , address1             = #{address1}
  , address2             = #{address2}
  , location_desc        = #{locationDesc}
  , grade                = #{grade}
  , preday               = #{preday}
  , able_ct              = #{ableCt}
  , able_mri             = #{ableMri}
  , able_park            = #{ablePark}
  , able_soup            = #{ableSoup}
  , able_satur           = #{ableSatur}
  , able_special         = #{ableSpecial}
  , able_am              = #{ableAm}
  , receipt_normal_begin = #{receiptNormalBegin}
  , receipt_normal_end   = #{receiptNormalEnd}
  , receipt_normal_pm_begin = #{receiptNormalPmBegin}
  , receipt_normal_pm_end = #{receiptNormalPmEnd}
  , receipt_satur_begin  = #{receiptSaturBegin}
  , receipt_satur_end    = #{receiptSaturEnd}
  , notes                = #{notes}
  , no_use               = #{noUse}
  , advertisement        = #{advertisement}
  , center_adv_filename1 = #{centerAdvFilename1}
  , center_adv_filename2 = #{centerAdvFilename2}
  , center_adv_filename3 = #{centerAdvFilename3}
  , center_adv_filename4 = #{centerAdvFilename4}
  , center_adv_filename5 = #{centerAdvFilename5}
  , center_adv_filename6 = #{centerAdvFilename6}
  , updated_at           = NOW()
  , updated_user_id      = #{sessionUserId}
WHERE center_id = #{centerId}

UPDATE hospital
SET hospital_code = #{hospitalCode}
  , hospital_name = #{hospitalName}
  , business_no   = #{businessNo}
  , ci_filename   = #{ciFilename}
WHERE hospital_id = #{hospitalId}

UPDATE user
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE center_id = #{centerId}

UPDATE platform_manager
SET deleted_at      = NOW()
  , deleted_user_id = #{sessionUserId}
WHERE center_id = #{centerId}

